# Backend configuration uses partial configuration.
# Initialize with: terraform init -backend-config=environments/<env>.backend.hcl
#
# State strategy: Single shared state for all modules (networking + aks).
# Both modules are tightly coupled (AKS depends on networking outputs) and
# managed by a team of 3. Shared state avoids terraform_remote_state complexity.
# See Story 1.2 Dev Notes — State Backend Strategy for alternatives.
terraform {
  backend "azurerm" {
    container_name = "tfstate"
    key            = "terraform.tfstate"
  }
}

