variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
}

variable "location" {
  description = "Azure region for resource deployment"
  type        = string
}

variable "resource_group_name" {
  description = "Name of the resource group for AKS resources"
  type        = string
}

# --------------------------------------------------------------------------
# AKS Cluster Configuration
# --------------------------------------------------------------------------

variable "kubernetes_version" {
  description = "Kubernetes version for the AKS cluster (1.32 recommended, LTS until July 2028)"
  type        = string
  default     = "1.32"
}

variable "aks_sku_tier" {
  description = "AKS SKU tier — Free (DEV), Standard (PRD, SLA-backed)"
  type        = string
  default     = "Free"
  validation {
    condition     = contains(["Free", "Standard"], var.aks_sku_tier)
    error_message = "AKS SKU tier must be 'Free' or 'Standard'."
  }
}

variable "aks_admin_group_object_ids" {
  description = "List of Azure AD group object IDs that will have cluster admin access"
  type        = list(string)
  default     = []
}

# --------------------------------------------------------------------------
# Networking (from Story 1.1 outputs)
# --------------------------------------------------------------------------

variable "aks_system_subnet_id" {
  description = "Resource ID of the AKS system node pool subnet (snet-aks-system-<env>)"
  type        = string
}

variable "aks_user_subnet_id" {
  description = "Resource ID of the AKS user node pool subnet (snet-aks-user-<env>)"
  type        = string
}

# --------------------------------------------------------------------------
# System Node Pool
# --------------------------------------------------------------------------

variable "system_node_pool_vm_size" {
  description = "VM size for the AKS system node pool"
  type        = string
  default     = "Standard_D4s_v3"
}

variable "system_node_pool_node_count" {
  description = "Number of nodes in the system node pool (min 2 for HA per NFR11)"
  type        = number
  default     = 2
  validation {
    condition     = var.system_node_pool_node_count >= 2
    error_message = "System node pool must have at least 2 nodes for HA (NFR11)."
  }
}

# --------------------------------------------------------------------------
# User (Workload) Node Pool
# --------------------------------------------------------------------------

variable "user_node_pool_vm_size" {
  description = "VM size for the user node pool — Python CronJob workloads"
  type        = string
  default     = "Standard_D4s_v5"
}

variable "user_node_pool_min_count" {
  description = "Minimum number of nodes for user pool autoscaling (NFR15)"
  type        = number
  default     = 3
}

variable "user_node_pool_max_count" {
  description = "Maximum number of nodes for user pool autoscaling (NFR15)"
  type        = number
  default     = 10
}

# --------------------------------------------------------------------------
# Azure Container Registry
# --------------------------------------------------------------------------

variable "acr_name" {
  description = "Name for the Azure Container Registry (no hyphens, globally unique)"
  type        = string
  validation {
    condition     = can(regex("^[a-zA-Z0-9]{5,50}$", var.acr_name))
    error_message = "ACR name must be 5-50 alphanumeric characters only (no hyphens)."
  }
}

variable "acr_sku" {
  description = "SKU for Azure Container Registry — Standard (DEV), Premium (PRD)"
  type        = string
  default     = "Premium"
  validation {
    condition     = contains(["Basic", "Standard", "Premium"], var.acr_sku)
    error_message = "ACR SKU must be 'Basic', 'Standard', or 'Premium'."
  }
}

# --------------------------------------------------------------------------
# Common
# --------------------------------------------------------------------------

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

