variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
}

variable "location" {
  description = "Azure region for resource deployment"
  type        = string
}

variable "resource_group_name" {
  description = "Name of the resource group for networking resources"
  type        = string
}

variable "vnet_address_space" {
  description = "Address space for the AKS VNet (CIDR notation)"
  type        = list(string)
}

variable "aks_system_subnet_cidr" {
  description = "CIDR block for the AKS system node pool subnet"
  type        = string
}

variable "aks_user_subnet_cidr" {
  description = "CIDR block for the AKS user node pool subnet"
  type        = string
}

variable "private_endpoints_subnet_cidr" {
  description = "CIDR block for private endpoints subnet"
  type        = string
}

variable "sap_vnet_id" {
  description = "Resource ID of the SAP VNet to peer with. Leave empty to skip peering."
  type        = string
  default     = ""
}

variable "sap_vnet_resource_group" {
  description = "Resource group containing the SAP VNet"
  type        = string
  default     = ""
}

variable "sap_dns_zone_name" {
  description = "Private DNS zone name for SAP hostname resolution"
  type        = string
  default     = "sap.internal"
}

variable "sap_dns_records" {
  description = "Map of SAP hostname to IP address for DNS A records"
  type        = map(string)
  default     = {}
}

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.60"
    }
  }
}

data "azurerm_client_config" "current" {}

locals {
  cluster_name = "aks-hypera-${var.environment}-${var.location}"
}

# --------------------------------------------------------------------------
# AKS Cluster (Task 2: AC 1, 2, 4)
# --------------------------------------------------------------------------
resource "azurerm_kubernetes_cluster" "main" {
  name                = local.cluster_name
  location            = var.location
  resource_group_name = var.resource_group_name
  dns_prefix          = "aks-hypera-${var.environment}"
  kubernetes_version  = var.kubernetes_version

  # Task 2.4: Standard (PRD, SLA-backed), Free (DEV)
  sku_tier = var.aks_sku_tier

  # Task 2.11: Force Azure AD authentication
  local_account_disabled = true

  # Task 2.6: Governance compliance
  azure_policy_enabled = true

  # Task 2.9: Managed Kubernetes upgrades
  automatic_upgrade_channel = "stable"

  # Task 2.3: Workload Identity for zero-trust pod auth (Story 3.1 dependency)
  oidc_issuer_enabled       = true
  workload_identity_enabled = true

  identity {
    type = "SystemAssigned"
  }

  # Task 2.1, 2.7, 2.8: System node pool — HA with critical addons only
  default_node_pool {
    name                         = "system"
    vm_size                      = var.system_node_pool_vm_size
    node_count                   = var.system_node_pool_node_count
    only_critical_addons_enabled = true
    vnet_subnet_id               = var.aks_system_subnet_id
    zones                        = ["1", "2", "3"]
    os_disk_type                 = "Managed"
    os_disk_size_gb              = 128
  }

  # Task 2.2: Azure CNI + Calico (IMMUTABLE after creation)
  network_profile {
    network_plugin = "azure"
    network_policy = "calico"
    outbound_type  = "loadBalancer"
  }

  # Task 2.12: Azure AD RBAC (managed = true implied in v4)
  azure_active_directory_role_based_access_control {
    azure_rbac_enabled     = true
    tenant_id              = data.azurerm_client_config.current.tenant_id
    admin_group_object_ids = var.aks_admin_group_object_ids
  }

  # Auto-scaler profile — CronJob workload optimized (Dev Notes best practices)
  auto_scaler_profile {
    scale_down_delay_after_add  = "10m"
    scale_down_unneeded         = "10m"
    skip_nodes_with_system_pods = true
    balance_similar_node_groups = true
    expander                    = "least-waste"
  }

  # Task 2.10: Off-hours maintenance window (weekends, night — Brazil time)
  maintenance_window {
    allowed {
      day   = "Saturday"
      hours = [0, 1, 2, 3, 4, 5]
    }
    allowed {
      day   = "Sunday"
      hours = [0, 1, 2, 3, 4, 5]
    }
  }

  tags = var.tags

  # Prevent plan drift: AKS auto-upgrades kubernetes_version when
  # automatic_upgrade_channel = "stable". Without this, the next plan
  # would try to downgrade back to var.kubernetes_version.
  lifecycle {
    ignore_changes = [kubernetes_version]
  }
}

