  default     = "Standard_D4s_v3"
}

variable "system_node_pool_node_count" {
  description = "Number of nodes in the system node pool (min 3 for HA across 3 AZs per NFR11)"
  type        = number
  default     = 3
  validation {
    condition     = var.system_node_pool_node_count >= 3
    error_message = "System node pool must have at least 3 nodes (one per AZ) for HA (NFR11)."
  }
}

# --------------------------------------------------------------------------
# User (Workload) Node Pool
# --------------------------------------------------------------------------

variable "user_node_pool_vm_size" {
  description = "VM size for the user node pool — Python CronJob workloads"
