  description = "Name for the Azure Container Registry (no hyphens, globally unique)"
  type        = string
  validation {
    condition     = can(regex("^[a-zA-Z0-9]{5,50}$", var.acr_name))
    error_message = "ACR name must be 5-50 alphanumeric characters only (no hyphens)."
  }
}

variable "acr_sku" {
  description = "SKU for Azure Container Registry — Standard (DEV), Premium (PRD)"
